"use client";

import { type ReactNode, useEffect, useState } from "react";

import { cn } from "../../lib/utils";
import { CopyButton } from "./code-tabs-copy-button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "./code-tabs-tabs";

export type CodeTabInput = {
  id: string;
  label: ReactNode;
  code: string;
  lang?: string;
};

export function CodeTabs({
  tabs,
  defaultValue,
  className,
}: {
  tabs: CodeTabInput[];
  defaultValue?: string;
  className?: string;
}) {
  const [highlighted, setHighlighted] = useState<Record<string, string>>({});

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const { codeToHtml } = await import("shiki/bundle/web");
        const entries = await Promise.all(
          tabs.map(async (tab) => {
            const html = await codeToHtml(tab.code, {
              lang: tab.lang ?? "tsx",
              themes: { light: "github-light", dark: "slack-dark" },
            });
            return [tab.id, html] as const;
          }),
        );
        if (!cancelled) setHighlighted(Object.fromEntries(entries));
      } catch {
        if (!cancelled) setHighlighted({});
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [tabs]);

  if (tabs.length === 0) return null;

  if (tabs.length === 1) {
    const tab = tabs[0];
    return (
      <div className={cn("relative overflow-x-auto rounded bg-zinc-900 p-4", className)}>
        <CopyButton classname="absolute right-2 top-2" code={tab.code} />
        {highlighted[tab.id] ? (
          <div dangerouslySetInnerHTML={{ __html: highlighted[tab.id] }} />
        ) : (
          <pre className="opacity-50">
            <code>{tab.code}</code>
          </pre>
        )}
      </div>
    );
  }

  const initialValue = tabs.some((tab) => tab.id === defaultValue) ? defaultValue : tabs[0].id;

  return (
    <Tabs
      className={cn("relative my-5 rounded-xl border bg-muted p-1 backdrop-blur-md", className)}
      defaultValue={initialValue}
    >
      <TabsList aria-label="Code examples" className="mx-1 mt-1 rounded-lg border-0 bg-transparent">
        {tabs.map((tab) => (
          <TabsTrigger
            className="gap-1 data-[state=active]:border data-[state=active]:bg-card"
            key={tab.id}
            value={tab.id}
          >
            {tab.label}
          </TabsTrigger>
        ))}
      </TabsList>

      {tabs.map((tab) => (
        <TabsContent className="mt-1 overflow-x-auto border-none" key={tab.id} value={tab.id}>
          <CopyButton classname="absolute right-3 top-1.5 border bg-card" code={tab.code} />
          {highlighted[tab.id] ? (
            <div
              className="cliblocks rounded-xl border-none px-2 py-1"
              dangerouslySetInnerHTML={{ __html: highlighted[tab.id] }}
            />
          ) : (
            <pre className="cliblocks rounded-xl px-2 py-1 opacity-50">
              <code>{tab.code}</code>
            </pre>
          )}
        </TabsContent>
      ))}
    </Tabs>
  );
}

"use client";

import * as TabsPrimitive from "@radix-ui/react-tabs";
import * as React from "react";

import { cn } from "../../lib/utils";

const Tabs = TabsPrimitive.Root;

const TabsList = React.forwardRef<
  React.ElementRef<typeof TabsPrimitive.List>,
  React.ComponentPropsWithoutRef<typeof TabsPrimitive.List>
>(({ className, ...props }, ref) => (
  <TabsPrimitive.List
    ref={ref}
    className={cn(
      "inline-flex h-10 items-center justify-center rounded-md border bg-input p-1 text-muted-foreground",
      className,
    )}
    {...props}
  />
));
TabsList.displayName = TabsPrimitive.List.displayName;

const TabsTrigger = React.forwardRef<
  React.ElementRef<typeof TabsPrimitive.Trigger>,
  React.ComponentPropsWithoutRef<typeof TabsPrimitive.Trigger>
>(({ className, ...props }, ref) => (
  <TabsPrimitive.Trigger
    ref={ref}
    className={cn(
      "inline-flex items-center justify-center whitespace-nowrap rounded-md px-3 py-2 text-sm font-medium ring-offset-background transition-all focus-visible:outline-hidden focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 data-[state=active]:bg-card data-[state=active]:text-foreground data-[state=active]:shadow-xs motion-reduce:transition-none",
      className,
    )}
    {...props}
  />
));
TabsTrigger.displayName = TabsPrimitive.Trigger.displayName;

interface TabsContentProps extends React.ComponentPropsWithoutRef<typeof TabsPrimitive.Content> {
  manualType?: boolean;
}

const TabsContent = React.forwardRef<
  React.ElementRef<typeof TabsPrimitive.Content>,
  TabsContentProps
>(({ className, manualType, ...props }, ref) => (
  <TabsPrimitive.Content
    ref={ref}
    className={cn(
      "mt-2 ring-offset-background focus-visible:outline-hidden focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
      className,
      manualType && "rounded-lg border bg-muted p-3",
    )}
    {...props}
  />
));
TabsContent.displayName = TabsPrimitive.Content.displayName;

export { Tabs, TabsContent, TabsList, TabsTrigger };

"use client";

import { CheckCheck, Copy } from "lucide-react";
import { useEffect, useRef, useState } from "react";

import { cn } from "../../lib/utils";

export function CopyButton({ code, classname }: { code: string; classname?: string }) {
  const [status, setStatus] = useState<"idle" | "copied" | "failed">("idle");
  const resetTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    return () => {
      if (resetTimer.current) clearTimeout(resetTimer.current);
    };
  }, []);

  const onCopy = async () => {
    try {
      await navigator.clipboard.writeText(code);
      setStatus("copied");
    } catch {
      setStatus("failed");
    }
    if (resetTimer.current) clearTimeout(resetTimer.current);
    resetTimer.current = setTimeout(() => setStatus("idle"), 1000);
  };

  return (
    <button
      aria-label={status === "copied" ? "Code copied" : status === "failed" ? "Copy failed" : "Copy code"}
      className={cn(
        "absolute right-2 top-2 grid h-8 w-9 cursor-pointer place-content-center rounded-md border-2 bg-card backdrop-blur-2xl transition-shadow hover:border-blue-300 hover:shadow-[0px_1px_10px_5px_#9abaf7] focus-visible:outline-2 focus-visible:outline-offset-2 motion-reduce:transition-none dark:hover:border-blue-500 dark:hover:shadow-[0px_1px_10px_5px_#3f7ef3]",
        classname,
      )}
      onClick={onCopy}
      type="button"
    >
      {status === "copied" ? (
        <CheckCheck aria-hidden="true" className="h-4 w-4 text-foreground/80" />
      ) : (
        <Copy aria-hidden="true" className="h-4 w-4 text-foreground/80" />
      )}
    </button>
  );
}

import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
